     1→<?php
     2→/**
     3→ * AgentPress Admin Interface
     4→ *
     5→ * Admin screen for AgentPress settings and log viewing.
     6→ *
     7→ * @package AgentPress
     8→ * @since 1.0.0
     9→ */
    10→
    11→namespace AgentPress;
    12→
    13→use AgentPress\Logger;
    14→
    15→/**
    16→ * Admin class for AgentPress.
    17→ */
    18→class Admin {
    19→
    20→    /**
    21→     * Menu slug for the admin page.
    22→     *
    23→     * @var string
    24→     */
    25→    const MENU_SLUG = 'agentpress';
    26→
    27→    /**
    28→     * Constructor.
    29→     */
    30→    public function __construct() {
    31→        add_action('admin_menu', array($this, 'add_admin_menu'));
    32→        add_action('admin_init', array($this, 'register_settings'));
    33→        add_action('admin_enqueue_scripts', array($this, 'enqueue_admin_scripts'));
    34→    }
    35→
    36→    /**
    37→     * Add the admin menu item.
    38→     */
    39→    public function add_admin_menu() {
    40→        add_submenu_page(
    41→            'tools.php',
    42→            __('AgentPress', 'agentpress'),
    43→            __('AgentPress', 'agentpress'),
    44→            'manage_options',
    45→            self::MENU_SLUG,
    46→            array($this, 'render_admin_page')
    47→        );
    48→    }
    49→
    50→    /**
    51→     * Register plugin settings.
    52→     */
    53→    public function register_settings() {
    54→        register_setting('agentpress_settings', 'agentpress_settings', array($this, 'sanitize_settings'));
    55→
    56→        // API Key field
    57→        add_settings_section(
    58→            'agentpress_api_section',
    59→            __('API Configuration', 'agentpress'),
    60→            array($this, 'render_api_section'),
    61→            'agentpress_settings'
    62→        );
    63→
    64→        add_settings_field(
    65→            'claude_api_key',
    66→            __('Claude API Key', 'agentpress'),
    67→            array($this, 'render_api_key_field'),
    68→            'agentpress_settings',
    69→            'agentpress_api_section'
    70→        );
    71→
    72→        add_settings_field(
    73→            'cf_worker_url',
    74→            __('Cloudflare Worker URL', 'agentpress'),
    75→            array($this, 'render_cf_worker_url_field'),
    76→            'agentpress_settings',
    77→            'agentpress_api_section'
    78→        );
    79→
    80→        add_settings_field(
    81→            'default_model',
    82→            __('Default Model', 'agentpress'),
    83→            array($this, 'render_default_model_field'),
    84→            'agentpress_settings',
    85→            'agentpress_api_section'
    86→        );
    87→    }
    88→
    89→    /**
    90→     * Sanitize settings.
    91→     *
    92→     * @param array $input Raw input settings.
    93→     * @return array Sanitized settings.
    94→     */
    95→    public function sanitize_settings($input) {
    96→        $sanitized = array();
    97→
    98→        // Sanitize Claude API key (password field, just keep as-is)
    99→        if (isset($input['claude_api_key'])) {
   100→            $sanitized['claude_api_key'] = $input['claude_api_key'];
   101→        }
   102→
   103→        // Sanitize Cloudflare Worker URL
   104→        if (isset($input['cf_worker_url'])) {
   105→            $url = esc_url_raw($input['cf_worker_url']);
   106→            if (!empty($url) && filter_var($url, FILTER_VALIDATE_URL)) {
   107→                $sanitized['cf_worker_url'] = $url;
   108→            } else {
   109→                add_settings_error(
   110→                    'agentpress_settings',
   111→                    'cf_worker_url',
   112→                    __('Invalid Cloudflare Worker URL. Please enter a valid URL.', 'agentpress')
   113→                );
   114→                $sanitized['cf_worker_url'] = '';
   115→            }
   116→        }
   117→
   118→        // Sanitize default model
   119→        if (isset($input['default_model'])) {
   120→            $valid_models = array('claude-3-5-sonnet-20241022', 'claude-3-opus-20240229', 'claude-3-sonnet-20240229');
   121→            if (in_array($input['default_model'], $valid_models, true)) {
   122→                $sanitized['default_model'] = $input['default_model'];
   123→            } else {
   124→                $sanitized['default_model'] = 'claude-3-5-sonnet-20241022';
   125→            }
   126→        }
   127→
   128→        return $sanitized;
   129→    }
   130→
   131→    /**
   132→     * Render the API section description.
   133→     */
   134→    public function render_api_section() {
   135→        echo '<p>' . esc_html__('Configure your API keys and worker endpoints below.', 'agentpress') . '</p>';
   136→    }
   137→
   138→    /**
   139→     * Render the Claude API key field.
   140→     */
   141→    public function render_api_key_field() {
   142→        $settings = get_option('agentpress_settings', array());
   143→        $value = isset($settings['claude_api_key']) ? $settings['claude_api_key'] : '';
   144→        $disabled = defined('AGENTPRESS_CLAUDE_KEY') ? 'disabled' : '';
   145→        $note = defined('AGENTPRESS_CLAUDE_KEY')
   146→            ? '<p class="description">' . __('Defined in wp-config.php with AGENTPRESS_CLAUDE_KEY constant.', 'agentpress') . '</p>'
   147→            : '';
   148→
   149→        printf(
   150→            '<input type="password" name="agentpress_settings[claude_api_key]" value="%s" %s class="regular-text" />%s',
   151→            esc_attr($value),
   152→            $disabled,
   153→            $note
   154→        );
   155→    }
   156→
   157→    /**
   158→     * Render the Cloudflare Worker URL field.
   159→     */
   160→    public function render_cf_worker_url_field() {
   161→        $settings = get_option('agentpress_settings', array());
   162→        $value = isset($settings['cf_worker_url']) ? $settings['cf_worker_url'] : '';
   163→        $disabled = defined('AGENTPRESS_CF_WORKER_URL') ? 'disabled' : '';
   164→        $note = defined('AGENTPRESS_CF_WORKER_URL')
   165→            ? '<p class="description">' . __('Defined in wp-config.php with AGENTPRESS_CF_WORKER_URL constant.', 'agentpress') . '</p>'
   166→            : '';
   167→
   168→        printf(
   169→            '<input type="url" name="agentpress_settings[cf_worker_url]" value="%s" %s class="regular-text" />%s',
   170→            esc_attr($value),
   171→            $disabled,
   172→            $note
   173→        );
   174→    }
   175→
   176→    /**
   177→     * Render the default model field.
   178→     */
   179→    public function render_default_model_field() {
   180→        $settings = get_option('agentpress_settings', array());
   181→        $value = isset($settings['default_model']) ? $settings['default_model'] : 'claude-3-5-sonnet-20241022';
   182→        $disabled = defined('AGENTPRESS_DEFAULT_MODEL') ? 'disabled' : '';
   183→        $note = defined('AGENTPRESS_DEFAULT_MODEL')
   184→            ? '<p class="description">' . __('Defined in wp-config.php with AGENTPRESS_DEFAULT_MODEL constant.', 'agentpress') . '</p>'
   185→            : '';
   186→
   187→        $models = array(
   188→            'claude-3-5-sonnet-20241022' => 'Claude 3.5 Sonnet (Recommended)',
   189→            'claude-3-opus-20240229' => 'Claude 3 Opus',
   190→            'claude-3-sonnet-20240229' => 'Claude 3 Sonnet',
   191→        );
   192→
   193→        echo '<select name="agentpress_settings[default_model]" ' . $disabled . '>';
   194→        foreach ($models as $model_value => $model_label) {
   195→            printf(
   196→                '<option value="%s" %s>%s</option>',
   197→                esc_attr($model_value),
   198→                selected($value, $model_value, false),
   199→                esc_html($model_label)
   200→            );
   201→        }
   202→        echo '</select>';
   203→        echo $note;
   204→    }
   205→
   206→    /**
   207→     * Enqueue admin scripts and styles.
   208→     *
   209→     * @param string $hook Current admin page.
   210→     */
   211→    public function enqueue_admin_scripts($hook) {
   212→        // Only load on AgentPress pages
   213→        if ($hook !== 'tools_page_agentpress') {
   214→            return;
   215→        }
   216→
   217→        // Enqueue CSS
   218→        wp_enqueue_style(
   219→            'agentpress-admin',
   220→            AGENTPRESS_PLUGIN_URL . 'admin/css/agentpress-admin.css',
   221→            array(),
   222→            AGENTPRESS_VERSION
   223→        );
   224→    }
   225→
   226→    /**
   227→     * Render the admin page.
   228→     */
   229→    public function render_admin_page() {
   230→        if (!current_user_can('manage_options')) {
   231→            return;
   232→        }
   233→
   234→        // Handle settings update
   235→        if (isset($_POST['action']) && $_POST['action'] === 'update') {
   236→            settings_errors('agentpress_settings');
   237→        }
   238→
   239→        ?>
   240→        <div class="wrap agentpress-wrap">
   241→            <h1><?php echo esc_html(get_admin_page_title()); ?></h1>
   242→
   243→            <div class="agentpress-section">
   244→                <h2 class="agentpress-section-title"><?php esc_html_e('Settings', 'agentpress'); ?></h2>
   245→
   246→                <form action="options.php" method="post" class="agentpress-form-table">
   247→                    <?php
   248→                    settings_fields('agentpress_settings');
   249→                    do_settings_sections('agentpress_settings');
   250→                    submit_button();
   251→                    ?>
   252→                </form>
   253→            </div>
   254→
   255→            <div class="agentpress-section">
   256→                <h2 class="agentpress-section-title"><?php esc_html_e('Recent Activity', 'agentpress'); ?></h2>
   257→
   258→                <?php $this->render_recent_logs(); ?>
   259→            </div>
   260→        </div>
   261→        <?php
   262→    }
   263→
   264→    /**
   265→     * Render recent logs table.
   266→     */
   267→    private function render_recent_logs() {
   268→        $logs = Logger::get_recent(50);
   269→
   270→        if (empty($logs)) {
   271→            printf(
   272→                '<p>%s</p>',
   273→                sprintf(
   274→                    /* translators: %s: API endpoint URL */
   275→                    __('No activity yet. Use the API endpoint at %s to start generating content and images.', 'agentpress'),
   276→                    '<code>' . esc_url(rest_url('agentpress/v1/run')) . '</code>'
   277→                )
   278→            );
   279→            return;
   280→        }
   281→
   282→        ?>
   283→        <table class="wp-list-table widefat fixed striped agentpress-log-table">
   284→            <thead>
   285→                <tr>
   286→                    <th><?php esc_html_e('Task', 'agentpress'); ?></th>
   287→                    <th><?php esc_html_e('Agent', 'agentpress'); ?></th>
   288→                    <th><?php esc_html_e('Status', 'agentpress'); ?></th>
   289→                    <th><?php esc_html_e('Latency', 'agentpress'); ?></th>
   290→                    <th><?php esc_html_e('Time', 'agentpress'); ?></th>
   291→                </tr>
   292→            </thead>
   293→            <tbody>
   294→                <?php foreach ($logs as $log): ?>
   295→                    <tr>
   296→                        <td>
   297→                            <?php
   298→                            $task = !empty($log['task']) ? $log['task'] : 'Unknown';
   299→                            echo esc_html(wp_trim_words($task, 10));
   300→                            ?>
   301→                        </td>
   302→                        <td>
   303→                            <strong><?php echo esc_html(ucfirst(str_replace('_', ' ', $log['capability']))); ?></strong>
   304→                            <?php if (!empty($log['routing_source'])): ?>
   305→                                <br>
   306→                                <span class="agentpress-routing-source">
   307→                                    <?php echo esc_html($log['routing_source']); ?>
   308→                                </span>
   309→                            <?php endif; ?>
   310→                        </td>
   311→                        <td>
   312→                            <?php
   313→                            $status_class = $log['status'] === 'success' ? 'success' : 'error';
   314→                            $status_label = $log['status'] === 'success' ? __('Success', 'agentpress') : __('Error', 'agentpress');
   315→                            ?>
   316→                            <span class="agentpress-status-pill agentpress-status-<?php echo esc_attr($status_class); ?>">
   317→                                <?php echo esc_html($status_label); ?>
   318→                            </span>
   319→                        </td>
   320→                        <td>
   321→                            <?php
   322→                            if (!empty($log['latency_ms'])) {
   323→                                echo esc_html(number_format($log['latency_ms'])) . ' ms';
   324→                            } else {
   325→                                echo '—';
   326→                            }
   327→                            ?>
   328→                        </td>
   329→                        <td>
   330→                            <?php
   331→                            $time = strtotime($log['date']);
   332→                            echo esc_html(sprintf(
   333→                                '%s ago',
   334→                                human_time_diff($time, current_time('timestamp'))
   335→                            ));
   336→                            ?>
   337→                        </td>
   338→                    </tr>
   339→                <?php endforeach; ?>
   340→            </tbody>
   341→        </table>
   342→        <?php
   343→    }
   344→}

